"use client";

import { useState, useRef, useEffect, useCallback } from "react";
import dynamic from "next/dynamic";
import { chatStream } from "@/lib/api";
import type { CanvasState } from "@/components/OmegaCanvas";
import Sidebar from "@/components/Sidebar/Sidebar";
import ChatHeader from "@/components/ChatHeader/ChatHeader";
import UserMessage from "@/components/MessageBubble/UserMessage";
import OmegaMessage from "@/components/MessageBubble/OmegaMessage";
import ThinkingIndicator from "@/components/MessageBubble/ThinkingIndicator";
import InputArea from "@/components/InputArea/InputArea";
import s from "./page.module.css";

const OmegaCanvas = dynamic(() => import("@/components/OmegaCanvas"), { ssr: false });

interface Msg {
  role: "user" | "omega";
  text: string;
  timestamp?: string;
  provider?: string;
}

export default function Home() {
  const [messages, setMessages] = useState<Msg[]>([]);
  const [animatingIdx, setAnimatingIdx] = useState(-1);
  const [error, setError] = useState<string | null>(null);
  const [canvasState, setCanvasState] = useState<CanvasState>("idle");
  const [statusText, setStatusText] = useState<string | null>(null);
  const [provider, setProvider] = useState<string | null>(null);
  const [sessionId, setSessionId] = useState<string | null>(null);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [sessionList, setSessionList] = useState<{ id: string; created_at: string; preview: string }[]>([]);
  const [showPill, setShowPill] = useState(false);

  const feedRef = useRef<HTMLDivElement>(null);
  const bottomRef = useRef<HTMLDivElement>(null);

  // Load saved session on mount
  useEffect(() => {
    const saved = localStorage.getItem("omega_session");
    if (saved) setSessionId(saved);
  }, []);

  // Fetch session list for sidebar
  const refreshSessions = useCallback(() => {
    fetch("/api/sessions")
      .then((r) => r.json())
      .then((data) => { if (Array.isArray(data)) setSessionList(data); })
      .catch(console.error);
  }, []);

  useEffect(() => { refreshSessions(); }, [refreshSessions]);

  // Scroll management
  const scrollToBottom = () => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
    setShowPill(false);
  };
  const handleScroll = () => {
    const el = feedRef.current;
    if (!el) return;
    setShowPill(el.scrollHeight - el.scrollTop - el.clientHeight > 50);
  };
  useEffect(() => {
    if (!showPill) bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, canvasState, showPill]);

  // Core send logic
  const sendMessage = useCallback(
    async (text: string) => {
      if (!text.trim() || canvasState === "thinking") return;
      setError(null);
      const newMsg: Msg = { role: "user", text, timestamp: new Date().toISOString() };
      const currentHistory = [...messages];
      setMessages((prev) => [...prev, newMsg]);
      setCanvasState("thinking");
      setShowPill(false);

      try {
        const res = await chatStream(
          { user: text, history: currentHistory, sessionId: sessionId ?? undefined },
          (chunk) => {
            setStatusText(null);
            setMessages((prev) => {
              const updated = [...prev];
              const last = updated[updated.length - 1];
              if (last.role === "user") {
                updated.push({ role: "omega", text: chunk, timestamp: new Date().toISOString() });
                setAnimatingIdx(updated.length - 1);
                setCanvasState("idle");
              } else {
                updated[updated.length - 1] = { ...last, text: last.text + chunk };
              }
              return updated;
            });
          },
          (status) => setStatusText(status)
        );

        if (res.sessionId && !sessionId) {
          setSessionId(res.sessionId);
          localStorage.setItem("omega_session", res.sessionId);
        }
        if (res.provider) setProvider(res.provider);

        // Tag the last omega message with provider
        setMessages((prev) => {
          const updated = [...prev];
          const last = updated[updated.length - 1];
          if (last.role === "omega") updated[updated.length - 1] = { ...last, provider: res.provider };
          return updated;
        });

        setAnimatingIdx(-1);
        setStatusText(null);
        refreshSessions();
      } catch (err) {
        setError(err instanceof Error ? err.message : String(err));
        setCanvasState("idle");
        setStatusText(null);
      }
    },
    [canvasState, messages, sessionId, refreshSessions]
  );

  const loadSession = async (id: string) => {
    try {
      const res = await fetch(`/api/sessions/${id}`);
      const data = await res.json();
      if (Array.isArray(data)) {
        setMessages(
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          data.map((m: any) => ({ role: m.role, text: m.content, timestamp: m.created_at }))
        );
        setSessionId(id);
        localStorage.setItem("omega_session", id);
        setSidebarOpen(false);
      }
    } catch (err) {
      console.error(err);
    }
  };

  const startNewChat = () => {
    setMessages([]);
    setAnimatingIdx(-1);
    setSessionId(null);
    setProvider(null);
    localStorage.removeItem("omega_session");
    setSidebarOpen(false);
  };

  // Close sidebar when clicking outside on mobile
  const handleMainClick = () => {
    if (sidebarOpen && window.innerWidth < 768) {
      setSidebarOpen(false);
    }
  };

  const hasMessages = messages.length > 0;

  // ── Render ──────────────────────────────────────────────────────
  return (
    <>
      <OmegaCanvas state={canvasState} />

      <div className={s.appLayout}>
        <Sidebar
          sessions={sessionList}
          activeSessionId={sessionId}
          onNewChat={startNewChat}
          onSelectSession={loadSession}
          isOpen={sidebarOpen}
          onToggle={() => setSidebarOpen((o) => !o)}
        />

        <div className={s.mainArea} onClick={handleMainClick}>
          <ChatHeader
            provider={provider ?? undefined}
            thinking={canvasState === "thinking"}
            onToggleSidebar={() => setSidebarOpen((o) => !o)}
            onNewChat={startNewChat}
          />

          <div
            className={s.feed}
            role="log"
            aria-live="polite"
            aria-label="Chat messages"
            ref={feedRef}
            onScroll={handleScroll}
          >
            {!hasMessages && (
              <div className={s.emptyState}>
                <div className={s.emptyOmega}>{"\u03A9"}</div>
                <div className={s.emptyLabel}>Ask OmegA anything</div>
              </div>
            )}

            {messages.map((msg, i) =>
              msg.role === "user" ? (
                <UserMessage key={i} text={msg.text} timestamp={msg.timestamp} />
              ) : (
                <OmegaMessage
                  key={i}
                  text={msg.text}
                  streaming={i === animatingIdx}
                  timestamp={msg.timestamp}
                  provider={msg.provider}
                />
              )
            )}

            {canvasState === "thinking" && <ThinkingIndicator status={statusText} />}

            {error && (
              <div className={s.error} role="alert">
                {error}
              </div>
            )}
            <div ref={bottomRef} style={{ height: 1 }} />
          </div>

          {showPill && (
            <div className={s.scrollPillWrap}>
              <button className={s.scrollPill} onClick={scrollToBottom} aria-label="Scroll to bottom">
                New response
              </button>
            </div>
          )}

          <InputArea
            onSend={sendMessage}
            disabled={canvasState === "thinking"}
            autoFocus
          />
        </div>
      </div>
    </>
  );
}
@import url('https://fonts.googleapis.com/css2?family=Orbitron:wght@400;700;900&family=Space+Grotesk:wght@300;400;500;600&display=swap');

:root {
  --void: #02020c;
  --indigo: #6366f1;
  --violet: #8b5cf6;
  --lavender: #c4b5fd;
  --gold: #e4b84a;
  --white: #f1f5f9;
  --dim: rgba(241, 245, 249, 0.45);
  --dimmer: rgba(241, 245, 249, 0.18);
  --glass-bg: rgba(8, 8, 28, 0.72);
  --glass-border: rgba(139, 92, 246, 0.18);
  --space-1: 0.25rem;
  --space-2: 0.5rem;
  --space-3: 0.75rem;
  --space-4: 1rem;
  --space-5: 1.5rem;
  --space-6: 2rem;
  --space-7: 3rem;
  --space-8: 4rem;
  --ease-snappy: cubic-bezier(0.16, 1, 0.3, 1);
  --ease-smooth: cubic-bezier(0.4, 0, 0.2, 1);
}

*:focus-visible {
  outline: 2px solid rgba(139, 92, 246, 0.6);
  outline-offset: 3px;
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

html, body {
  height: 100%;
  overflow: hidden;
  background: var(--void);
  color: var(--white);
  font-family: 'Space Grotesk', system-ui, sans-serif;
  -webkit-font-smoothing: antialiased;
  overscroll-behavior: none;
}

/* Scrollbar */
::-webkit-scrollbar { width: 3px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: rgba(139, 92, 246, 0.3); border-radius: 2px; }

/* ── Keyframes ───────────────────────────────────────────────────── */

@keyframes omega-breathe {
  0%, 100% { filter: drop-shadow(0 0 18px rgba(99,102,241,0.6)) drop-shadow(0 0 50px rgba(139,92,246,0.25)); }
  50%       { filter: drop-shadow(0 0 30px rgba(139,92,246,0.9)) drop-shadow(0 0 80px rgba(99,102,241,0.35)); }
}

@keyframes omega-think {
  0%   { filter: drop-shadow(0 0 20px rgba(228,184,74,0.5)) drop-shadow(0 0 60px rgba(228,184,74,0.2)); transform: scale(1) rotate(0deg); }
  25%  { filter: drop-shadow(0 0 40px rgba(228,184,74,0.9)) drop-shadow(0 0 100px rgba(228,184,74,0.4)); transform: scale(1.04) rotate(1deg); }
  75%  { filter: drop-shadow(0 0 40px rgba(228,184,74,0.9)) drop-shadow(0 0 100px rgba(228,184,74,0.4)); transform: scale(1.04) rotate(-1deg); }
  100% { filter: drop-shadow(0 0 20px rgba(228,184,74,0.5)) drop-shadow(0 0 60px rgba(228,184,74,0.2)); transform: scale(1) rotate(0deg); }
}

@keyframes omega-respond {
  0%   { filter: drop-shadow(0 0 30px rgba(196,181,253,0.8)) drop-shadow(0 0 80px rgba(196,181,253,0.4)); }
  100% { filter: drop-shadow(0 0 18px rgba(99,102,241,0.6)) drop-shadow(0 0 50px rgba(139,92,246,0.25)); }
}

@keyframes fade-up {
  from { opacity: 0; transform: translateY(12px); }
  to   { opacity: 1; transform: translateY(0); }
}

@keyframes cursor-blink {
  0%, 100% { opacity: 1; }
  50%       { opacity: 0; }
}

@keyframes shimmer {
  0%   { background-position: -200% center; }
  100% { background-position:  200% center; }
}

@keyframes ring-pulse {
  0%   { transform: scale(1); opacity: 0.6; }
  100% { transform: scale(2.2); opacity: 0; }
}

@keyframes dot-bounce {
  0%, 80%, 100% { transform: translateY(0); opacity: 0.3; }
  40%            { transform: translateY(-6px); opacity: 1; }
}

/* ── Reduced motion ─────────────────────────────────────────────── */
@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    opacity: 1 !important;
  }
}

