/* ── Overlay (mobile) ─────────────────────────────────────── */
.overlay {
  display: none;
}

@media (max-width: 767px) {
  .overlay {
    display: block;
    position: fixed;
    inset: 0;
    background: rgba(2, 2, 12, 0.6);
    backdrop-filter: blur(4px);
    z-index: 998;
    animation: fadeIn 0.2s ease;
  }
}

@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

/* ── Sidebar ─────────────────────────────────────────────── */
.sidebar {
  position: relative;
  top: 0;
  left: 0;
  bottom: 0;
  width: 280px;
  flex-shrink: 0;
  z-index: 999;
  display: flex;
  flex-direction: column;
  background: var(--glass-bg);
  border-right: 1px solid var(--glass-border);
  backdrop-filter: blur(24px) saturate(1.4);
  -webkit-backdrop-filter: blur(24px) saturate(1.4);
  transition: width 0.3s cubic-bezier(0.4, 0, 0.2, 1), transform 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  overflow: hidden;
}

/* Desktop: collapsed = zero width */
@media (min-width: 768px) {
  .sidebar {
    width: 0;
    min-width: 0;
  }
  .sidebarOpen {
    width: 280px;
  }
}

/* Mobile: slide from left */
@media (max-width: 767px) {
  .sidebar {
    position: fixed;
    width: 280px;
    transform: translateX(-100%);
  }

  .sidebarOpen {
    transform: translateX(0);
  }
}

/* ── Brand ───────────────────────────────────────────────── */
.brand {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 24px 20px 16px;
  flex-shrink: 0;
  white-space: nowrap;
}

.omega {
  font-family: 'Orbitron', sans-serif;
  font-size: 32px;
  font-weight: 700;
  color: var(--indigo);
  animation: breathe 4s ease-in-out infinite;
  text-shadow: 0 0 20px rgba(99, 102, 241, 0.4), 0 0 40px rgba(99, 102, 241, 0.15);
  line-height: 1;
  flex-shrink: 0;
}

@keyframes breathe {
  0%, 100% { opacity: 0.85; text-shadow: 0 0 20px rgba(99, 102, 241, 0.4), 0 0 40px rgba(99, 102, 241, 0.15); }
  50% { opacity: 1; text-shadow: 0 0 30px rgba(99, 102, 241, 0.6), 0 0 60px rgba(99, 102, 241, 0.25); }
}

.brandName {
  font-family: 'Orbitron', sans-serif;
  font-size: 18px;
  font-weight: 600;
  color: var(--white);
  letter-spacing: 2px;
}

.toggle {
  margin-left: auto;
  background: none;
  border: none;
  color: var(--dim);
  font-size: 20px;
  cursor: pointer;
  padding: 4px 8px;
  border-radius: 6px;
  transition: color 0.2s, background 0.2s;
  flex-shrink: 0;
}

.toggle:hover {
  color: var(--white);
  background: rgba(241, 245, 249, 0.06);
}

/* ── New Chat ────────────────────────────────────────────── */
.newChat {
  margin: 0 16px 12px;
  padding: 12px 16px;
  border: 1px solid rgba(99, 102, 241, 0.35);
  border-radius: 10px;
  background: rgba(99, 102, 241, 0.06);
  color: var(--lavender);
  font-family: 'Space Grotesk', sans-serif;
  font-size: 14px;
  font-weight: 500;
  cursor: pointer;
  display: flex;
  align-items: center;
  gap: 8px;
  transition: all 0.25s ease;
  flex-shrink: 0;
  position: relative;
  overflow: hidden;
  white-space: nowrap;
}

.newChat::before {
  content: "";
  position: absolute;
  inset: -1px;
  border-radius: 10px;
  padding: 1px;
  background: linear-gradient(135deg, var(--indigo), var(--violet));
  -webkit-mask: linear-gradient(#fff 0 0) content-box, linear-gradient(#fff 0 0);
  -webkit-mask-composite: xor;
  mask-composite: exclude;
  opacity: 0;
  transition: opacity 0.3s ease;
}

.newChat:hover::before {
  opacity: 1;
}

.newChat:hover {
  background: rgba(99, 102, 241, 0.12);
  border-color: var(--indigo);
  box-shadow: 0 0 24px rgba(99, 102, 241, 0.15);
  color: var(--white);
}

.newChatIcon {
  font-size: 18px;
  font-weight: 300;
}

/* ── Divider ─────────────────────────────────────────────── */
.divider {
  height: 1px;
  margin: 0 20px 8px;
  background: linear-gradient(90deg, transparent, var(--glass-border), transparent);
  flex-shrink: 0;
}

/* ── Session Label ───────────────────────────────────────── */
.sectionLabel {
  padding: 4px 20px 8px;
  font-family: 'Space Grotesk', sans-serif;
  font-size: 10px;
  font-weight: 600;
  letter-spacing: 1.5px;
  text-transform: uppercase;
  color: var(--dimmer);
  flex-shrink: 0;
  white-space: nowrap;
}

/* ── Session List ────────────────────────────────────────── */
.sessionList {
  flex: 1;
  overflow-y: auto;
  padding: 0 8px 16px;
  scroll-behavior: smooth;
}

/* Custom scrollbar */
.sessionList::-webkit-scrollbar {
  width: 4px;
}

.sessionList::-webkit-scrollbar-track {
  background: transparent;
}

.sessionList::-webkit-scrollbar-thumb {
  background: var(--dimmer);
  border-radius: 4px;
}

.sessionList::-webkit-scrollbar-thumb:hover {
  background: var(--dim);
}

.empty {
  padding: 24px 16px;
  text-align: center;
  font-family: 'Space Grotesk', sans-serif;
  font-size: 13px;
  color: var(--dimmer);
  line-height: 1.5;
  white-space: normal;
}

/* ── About Section ───────────────────────────────────────── */
.aboutSection {
  flex-shrink: 0;
  padding: 0 0 20px;
  display: flex;
  flex-direction: column;
}

.aboutLink {
  display: block;
  padding: 6px 20px;
  font-family: 'Space Grotesk', sans-serif;
  font-size: 12px;
  color: var(--dim);
  text-decoration: none;
  transition: color 0.2s ease;
  white-space: nowrap;
}

.aboutLink:hover {
  color: var(--lavender);
}
.header {
  position: sticky;
  top: 0;
  z-index: 50;
  background: var(--glass-bg, rgba(8, 8, 28, 0.72));
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
}

.header.thinking {
  box-shadow: 0 0 30px rgba(228, 184, 74, 0.06);
}

.inner {
  display: flex;
  align-items: center;
  gap: 0.65rem;
  padding: 0.65rem 1.25rem;
}

/* ── Hamburger (mobile) ─────────────────────────────────────────── */
.hamburger {
  display: none;
  flex-direction: column;
  gap: 4px;
  background: none;
  border: none;
  cursor: pointer;
  padding: 0.25rem;
  transition: opacity 0.25s ease;
}

.hamburger span {
  display: block;
  width: 18px;
  height: 2px;
  background: var(--dim, rgba(241, 245, 249, 0.45));
  border-radius: 1px;
  transition: background 0.25s ease;
}

.hamburger:hover span {
  background: var(--lavender, #c4b5fd);
}

@media (max-width: 768px) {
  .hamburger {
    display: flex;
  }
}

/* ── Branding ───────────────────────────────────────────────────── */
.glyph {
  font-family: 'Orbitron', sans-serif;
  font-size: 1.35rem;
  font-weight: 800;
  background: linear-gradient(135deg, #6366f1, #8b5cf6);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  transition: filter 0.3s ease;
}

.glyphThinking {
  animation: glyphPulse 1.8s ease-in-out infinite;
}

@keyframes glyphPulse {
  0%, 100% { filter: drop-shadow(0 0 6px rgba(228, 184, 74, 0.3)); }
  50% { filter: drop-shadow(0 0 16px rgba(228, 184, 74, 0.6)); }
}

.title {
  font-family: 'Orbitron', sans-serif;
  font-size: 1rem;
  font-weight: 700;
  color: var(--white, #f1f5f9);
  letter-spacing: 0.04em;
}

/* ── Provider badge ─────────────────────────────────────────────── */
.providerBadge {
  font-family: 'Space Grotesk', monospace;
  font-size: 0.6rem;
  padding: 0.12rem 0.45rem;
  border-radius: 0.3rem;
  background: rgba(99, 102, 241, 0.1);
  border: 1px solid rgba(99, 102, 241, 0.2);
  color: var(--dim, rgba(241, 245, 249, 0.45));
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.spacer {
  flex: 1;
}

/* ── Status ─────────────────────────────────────────────────────── */
.statusGroup {
  display: flex;
  align-items: center;
  gap: 0.4rem;
  font-family: 'Space Grotesk', sans-serif;
  font-size: 0.72rem;
  color: var(--dim, rgba(241, 245, 249, 0.45));
}

.statusDot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: #22c55e;
  box-shadow: 0 0 8px rgba(34, 197, 94, 0.4);
}

.statusLabel {
  letter-spacing: 0.04em;
}

/* ── New chat button ────────────────────────────────────────────── */
.newBtn {
  font-family: 'Space Grotesk', sans-serif;
  font-size: 0.72rem;
