            fullResponse += decoder.decode(value, { stream: true });
            controller.enqueue(value);
          }
          fullResponse += decoder.decode();

          // Save history asynchronously
          if (dbUrl && finalSessionId && fullResponse) {
            const db = neon(dbUrl);
