              responseStream = new ReadableStream({
                async start(ctrl) {
                  for await (const chunk of vercelResult.textStream) {
                    if (chunk) ctrl.enqueue(encoder.encode(chunk));
                  }
                  ctrl.close();
                }
              });
            } else {
            const Key = process.env._API_KEY ?? process.env.NEXT_PUBLIC__API_KEY;
