              namespace: 'synthesis',
              use_memory: false,
              temperature: 0.85,
              mode: 'omega',
              system,
              stream: true
            }));

            if (!upstream.ok) throw new Error(`Gateway: ${upstream.status}`);
            if (!upstream.body) throw new Error("Gateway empty body");
            responseStream = upstream.body;

          } catch (err) {
            const vercelGatewayKey = process.env.VERCEL_AI_GATEWAY_KEY;
            if (vercelGatewayKey) {
              console.warn('[OmegA chat] Vercel AI Gateway fallback active:', err);
              provider = "vercel-ai-gateway";
              const vercelAI = createOpenAI({
                baseURL: 'https://ai-gateway.vercel.sh/v1',
                apiKey: vercelGatewayKey,
              });
              const vercelMessages: { role: 'user' | 'assistant'; content: string }[] = [
