  for (let attempt = 0; attempt <= GATEWAY_RETRIES; attempt++) {
    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), GATEWAY_TIMEOUT_MS);

    try {
      const res = await fetch(`${GATEWAY}/api/v1/chat`, {
