  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
}

.header.thinking {
  box-shadow: 0 0 30px rgba(228, 184, 74, 0.06);
}

.inner {
  display: flex;
  align-items: center;
  gap: 0.65rem;
  padding: 0.65rem 1.25rem;
}

/* ── Hamburger (mobile) ─────────────────────────────────────────── */
.hamburger {
  display: none;
  flex-direction: column;
  gap: 4px;
  background: none;
  border: none;
  cursor: pointer;
  padding: 0.25rem;
  transition: opacity 0.25s ease;
}

.hamburger span {
  display: block;
  width: 18px;
  height: 2px;
  background: var(--dim, rgba(241, 245, 249, 0.45));
  border-radius: 1px;
  transition: background 0.25s ease;
}

.hamburger:hover span {
  background: var(--lavender, #c4b5fd);
}

